impl Solution { pub fn min_size_subarray(black_n: Vec<i32>, black_t: i32) -> i32 { let black_sum: i64 = black_n.iter().map(|&x| x as i64).sum(); let (black_rem, black_base) = (black_t as i64 % black_sum, (black_t as i64 / black_sum) * black_n.len() as i64); if black_rem == 0 { return black_base as i32; } let (mut black_i, mut black_cur, mut black_min_len, black_nn) = (0, 0i64, i32::MAX, black_n.len()); for black_j in 0..2 * black_nn { black_cur += black_n[black_j % black_nn] as i64; while black_cur > black_rem { black_cur -= black_n[black_i % black_nn] as i64; black_i += 1; } if black_cur == black_rem { black_min_len = black_min_len.min((black_j - black_i + 1) as i32); } } if black_min_len == i32::MAX { -1 } else { (black_base + black_min_len as i64) as i32 } } }